// BAD: matches by index. Reorder data and everything breaks.
svg.selectAll("rect")
  .data(data)
  .join("rect");

// GOOD: matches by unique ID. Reorder all you want.
svg.selectAll("rect")
  .data(data, d => d.id)
  .join("rect");

const line = d3.line()
  .x(d => xScale(d.date))
  .y(d => yScale(d.value))
  .curve(d3.curveCardinal.tension(0.5));

svg.append("path")
  .datum(data)
  .attr("d", line)
  .attr("fill", "none")
  .attr("stroke", "steelblue");

const pie = d3.pie()
  .value(d => d.revenue)
  .sort(null);              // keep original order

const arc = d3.arc()
  .innerRadius(50)          // > 0 = donut
  .outerRadius(150);

// pie(data) returns array with startAngle, endAngle
// arc(pieSlice) returns the path string
svg.selectAll("path")
  .data(pie(data))
  .join("path")
  .attr("d", arc);

function update(data) {
  svg.selectAll("rect")
    .data(data)
    .enter()
    .append("rect")
    .attr("x", (d, i) => xScale(i))
    .attr("y", d => yScale(d.value))
    .attr("width", xScale.bandwidth())
    .attr("height", d => height - yScale(d.value));
}

